import React, { useState, useEffect } from 'react';
import { useLocation, useParams, useNavigate } from 'react-router-dom';

const StudySession = ({ markDayComplete }) => {
  const { day } = useParams();
  const { state } = useLocation();
  const navigate = useNavigate();

  // 1. SET THE TOTAL TIME (e.g., 45 minutes = 2700 seconds)
  const TOTAL_TIME = 2700; 
  const [timeLeft, setTimeLeft] = useState(TOTAL_TIME);
  const [isActive, setIsActive] = useState(false);
  const [sessionFinished, setSessionFinished] = useState(false);
  const [userAnswer, setUserAnswer] = useState('');

  useEffect(() => {
    let interval = null;
    if (isActive && timeLeft > 0) {
      interval = setInterval(() => {
        setTimeLeft((prev) => prev - 1);
      }, 1000);
    } else if (timeLeft === 0) {
      // ONLY when timeLeft is exactly 0, we allow completion
      setSessionFinished(true);
      setIsActive(false);
      clearInterval(interval);
    }
    return () => clearInterval(interval);
  }, [isActive, timeLeft]);

  const formatTime = (seconds) => {
    const mins = Math.floor(seconds / 60);
    const secs = seconds % 60;
    return `${mins}m ${secs < 10 ? '0' : ''}${secs}s`;
  };

  const handleFinalSubmit = () => {
    if (userAnswer.length < 30) {
      alert("The AI requires a more detailed explanation of your practice session.");
      return;
    }
    markDayComplete(day);
    navigate('/dashboard');
  };

  return (
    <div style={{ padding: '40px', fontFamily: 'Arial', textAlign: 'center', backgroundColor: '#f4f7f6', minHeight: '100vh' }}>
      <div style={{ maxWidth: '600px', margin: '0 auto', background: 'white', padding: '30px', borderRadius: '15px', boxShadow: '0 10px 30px rgba(0,0,0,0.1)' }}>
        
        <h2 style={{ color: '#2c3e50' }}>Day {day}: {state?.topic}</h2>
        
        {/* Progress Ring or Bar could go here */}
        <div style={{ 
          fontSize: '70px', 
          margin: '30px 0', 
          fontWeight: 'bold', 
          color: timeLeft === 0 ? '#27ae60' : '#e67e22' 
        }}>
          {formatTime(timeLeft)}
        </div>

        {!sessionFinished ? (
          <div style={{ padding: '20px', border: '2px dashed #bdc3c7', borderRadius: '10px' }}>
            <p style={{ color: '#7f8c8d', marginBottom: '20px' }}>
              <strong>Focus Mode Active:</strong> The "Complete" button is locked. 
              Please use this time to read the documentation and practice coding.
            </p>
            
            <button 
              onClick={() => setIsActive(!isActive)}
              style={{ 
                padding: '15px 30px', 
                fontSize: '18px', 
                borderRadius: '8px', 
                border: 'none', 
                backgroundColor: isActive ? '#e74c3c' : '#2ecc71', 
                color: 'white', 
                cursor: 'pointer' 
              }}
            >
              {isActive ? 'Pause Timer' : 'Start Focus Session'}
            </button>
            
            <div style={{ marginTop: '20px', fontSize: '14px', color: '#95a5a6' }}>
              Completion will unlock when the timer hits 00:00.
            </div>
          </div>
        ) : (
          /* THIS SECTION ONLY APPEARS AFTER THE TIME IS UP */
          <div style={{ textAlign: 'left', animation: 'fadeIn 0.8s' }}>
            <div style={{ backgroundColor: '#d4edda', color: '#155724', padding: '15px', borderRadius: '8px', marginBottom: '20px' }}>
              <strong>Time Complete!</strong> You have shown discipline. Now, verify your learning.
            </div>
            
            <label style={{ fontWeight: 'bold' }}>AI Knowledge Check:</label>
            <p style={{ fontSize: '14px', color: '#555' }}>Describe the most difficult part of {state?.topic} you encountered during this 45-minute block.</p>
            
            <textarea 
              value={userAnswer}
              onChange={(e) => setUserAnswer(e.target.value)}
              placeholder="Write your reflection here..."
              style={{ width: '100%', height: '120px', padding: '10px', borderRadius: '8px', border: '1px solid #ddd', marginTop: '10px' }}
            />

            <button 
              onClick={handleFinalSubmit}
              style={{ width: '100%', padding: '15px', marginTop: '15px', borderRadius: '8px', border: 'none', backgroundColor: '#2c3e50', color: 'white', cursor: 'pointer', fontWeight: 'bold' }}
            >
              Submit & Finalize Day {day}
            </button>
          </div>
        )}
      </div>
    </div>
  );
};

export default StudySession;
